+// Replace all occurrences of 'LHS' with 'RHS' everywhere in the scope.  As
+// LHS always has at least one use that is not dominated by Root, this will
+// never do anything if LHS has only one use.
+if (!LHS->hasOneUse()) {
+  // Create a callback that captures the DL.
+  auto CanReplacePointersCallBack = [&DL](const Use &U, const Value *To) {
+    // Allow replacing pointer operand for volatile stores.
+    if (const Instruction *UserI2 = dyn_cast<Instruction>(U.getUser())) {
+      if (const StoreInst *SI = dyn_cast<StoreInst>(UserI2)) {
+        if (SI->isVolatile())
+          return true;
+      }
+    }
+    // Do not substitute the pointer operand of lifetime intrinsics. The verifier
+    // requires llvm.lifetime.start/end to operate on an alloca or poison.
+    if (const Instruction *UserI = dyn_cast<Instruction>(U.getUser())) {
+      if (const IntrinsicInst *II = dyn_cast<IntrinsicInst>(UserI)) {
+        Intrinsic::ID ID = II->getIntrinsicID();
+        if (ID == Intrinsic::lifetime_start || ID == Intrinsic::lifetime_end) {
+          // Operand 1 is the pointer argument for lifetime intrinsics.
+          if (U.getOperandNo() == 1)
+            return false;
+        }
       }
     }
+    return canReplacePointersInUseIfEqual(U, To, DL);
+  };
+  unsigned NumReplacements =
+      DominatesByEdge
+          ? replaceDominatedUsesWithIf(LHS, RHS, *DT, Root,
+                                       CanReplacePointersCallBack)
+          : replaceDominatedUsesWithIf(LHS, RHS, *DT, Root.getStart(),
+                                       CanReplacePointersCallBack);
+
+  if (NumReplacements > 0) {
+    Changed = true;
+    NumGVNEqProp += NumReplacements;
+    // Cached information for anything that uses LHS will be invalid.
+    if (MD)
+      MD->invalidateCachedPointerInfo(LHS);
+  }
+}
